/**
 * @summary Twilio WhatsApp inbound webhook
 */
export const getWhatsappWebhookUrl = () => {
  return `/api/whatsapp/webhook`;
};

export const whatsappWebhook = async (
  whatsappWebhookBody: WhatsappWebhookBody,
  options?: RequestInit,
): Promise<string> => {
  const formUrlEncoded = new URLSearchParams();
  if (whatsappWebhookBody.From !== undefined) {
    formUrlEncoded.append(`From`, whatsappWebhookBody.From);
  }
  if (whatsappWebhookBody.Body !== undefined) {
    formUrlEncoded.append(`Body`, whatsappWebhookBody.Body);
  }

  return customFetch<string>(getWhatsappWebhookUrl(), {
    ...options,
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
      ...options?.headers,
    },
    body: formUrlEncoded,
  });
};

